const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || response.message?.content || '{}';

let topics;
try {
  topics = JSON.parse(content);
  if (!Array.isArray(topics)) topics = [topics];
} catch (e) {
  const match = content.match(/\[.*\]/s);
  topics = match ? JSON.parse(match[0]) : [{ topic: content, angle: 'General insight', key_insight: content, personal_tie_in: '', hormozi_framework: 'value_equation', framework_visual: 'architecture' }];
}

return topics.map(t => ({ json: { ...t, meeting_record_id: $node['Fetch Unprocessed Meetings'].json.id, rag_context: $node['RAG Personal Context'].json } }));

